mapper.select:
select w.id, w.project_id, w.user_id, w.category_id, w.internal_workload, w.external_workload, w.internal_price, w.external_price, w.internal_output, w.external_output, w.price_source, w.extra_data::text as extra_data, w.del_flag, w.create_by, w.create_time, w.update_by, w.update_time, w.remark, p.project_name, u.user_name, c.name as category_name from proj_workload w left join proj_project p on p.id = w.project_id left join sys_user u on u.user_id = w.user_id left join proj_category c on c.id = w.category_id where w.del_flag = '0'
and w.project_id = #{projectId}
and w.user_id = #{userId}
and w.category_id = #{categoryId}
and w.price_source = #{priceSource}
order by w.id desc

mapper.update:
update proj_workload
project_id = #{projectId}, user_id = #{userId}, category_id = #{categoryId}, internal_workload = #{internalWorkload}, external_workload = #{externalWorkload}, internal_price = #{internalPrice}, external_price = #{externalPrice}, internal_output = #{internalOutput}, external_output = #{externalOutput}, price_source = #{priceSource}, extra_data = #{extraData}::jsonb, remark = #{remark}, update_by = #{updateBy}, update_time = now()
where id = #{id}
